def range_summary(nums):
    runs = []
    for i in range(1, len(nums)):
        if nums[i] == nums[i - 1] + 1:
            continue
        else:
            runs.append((nums[i-1], nums[i] - 1))
    runs.append(nums[-1])
    return ', '.join('-'.join(str(x) for x in run) if isinstance(run, tuple) else str(run) for run in runs)
